fd.rendered(function() {
    //disable fields
    fd.field('Date').disabled = true;

    //set CompletionDate to the current date
    fd.field('Date').value = new Date();


    // add validation for Consent
    fd.field('Consent').addValidator({
        name: 'ConsentValidator',
        error: 'You must check all points. If you still have questions, contact your family doctor.',
        validate: function(value) {
            if (fd.field('Consent').value.length < 5)
                return false;

            return true;
        }
    });    
    
    fd.field('BirthDate').widgetOptions = {
        start: 'decade'
    }
});

css:
/** h1 text color to white **/
.fd-form h1 {
    color: white !important;
}

/** styling of the disable Date field **/

.fd-form .completion-date .fd-field-control:disabled,
.fd-form .completion-date .fd-field-control[readonly],
.fd-form .completion-date .k-datepicker {
    background: none;
    border: none;
    font-weight: bold;
}

.fd-form .completion-date .k-input-button {
    display: none !important;
}

.fd-form .completion-date input {
    padding-left: 0px;
}

/** add top dorder to the main container **/
.fd-form .main-container {
    border-top: 20px solid rgba(var(--fd-primary-rgb)) !important;
}
